use anyhow::{Context, Result};
use clap::Parser;
use log::{error, info, warn};
use notify::{Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::mpsc;

#[derive(Parser, Debug)]
#[command(version, about)]
struct Args {
    /// Directories to monitor
    #[arg(required = true)]
    directories: Vec<PathBuf>,

    /// Backup directory path
    #[arg(short, long, required = true)]
    backup: PathBuf,
}

async fn copy_file(src: &Path, dest: &Path) -> Result<()> {
    let parent = dest.parent().context("Invalid destination path")?;
    std::fs::create_dir_all(parent)?;
    std::fs::copy(src, dest).with_context(|| format!("Failed to copy {:?}", src))?;

    let permissions = std::fs::metadata(src)
        .with_context(|| format!("Failed to get permissions for {:?}", src))?
        .permissions();
    std::fs::set_permissions(dest, permissions)
        .with_context(|| format!("Failed to set permissions for {:?}", dest))?;

    Ok(())
}

async fn handle_event(event: Event, backup_root: &Path) {
    let paths = event.paths.iter().filter_map(|p| {
        if p.is_file() {
            Some((p.to_owned(), backup_root.join(p.strip_prefix("/").unwrap_or(p))))
        } else {
            None
        }
    });

    for (src, dest) in paths {
        match event.kind {
            EventKind::Create(_) | EventKind::Modify(_) => {
                if let Err(e) = copy_file(&src, &dest).await {
                    error!("Sync error: {}", e);
                } else {
                    info!("Synced {:?} to {:?}", src, dest);
                }
            }
            EventKind::Remove(_) => {
                if let Err(e) = std::fs::remove_file(&dest)
                    .with_context(|| format!("Failed to remove {:?}", dest))
                {
                    error!("{}", e);
                } else {
                    info!("Removed {:?}", dest);
                }
            }
            _ => {}
        }
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    env_logger::init();
    let args = Args::parse();

    std::fs::create_dir_all(&args.backup)
        .with_context(|| format!("Failed to create backup directory {:?}", args.backup))?;

    let (tx, mut rx) = mpsc::unbounded_channel();
    let backup = Arc::new(args.backup.clone());

    let mut watcher = RecommendedWatcher::new(
        move |res: Result<Event, notify::Error>| {
            if let Ok(event) = res {
                let _ = tx.send(event);
            }
        },
        notify::Config::default(),
    )?;

    for dir in &args.directories {
        watcher.watch(dir.as_path(), RecursiveMode::Recursive)?;
        info!("Watching directory: {:?}", dir);
    }

    while let Some(event) = rx.recv().await {
        let backup = Arc::clone(&backup);
        tokio::spawn(async move {
            handle_event(event, &backup).await;
        });
    }

    Ok(())
}
