```rust
use anyhow::{Context, Result};
use notify::{Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::{
    collections::HashSet,
    env,
    path::{Path, PathBuf},
    sync::{Arc, Mutex},
    thread,
};

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    let dir = args.get(1).context("Provide directory to monitor")?;
    let dir_path = Path::new(dir);

    let (tx, rx) = crossbeam_channel::unbounded();
    let mut watcher: RecommendedWatcher = Watcher::new(tx, notify::Config::default())?;
    watcher.watch(dir_path, RecursiveMode::NonRecursive)?;

    let processed_files = Arc::new(Mutex::new(HashSet::new()));

    for event in rx {
        let processed = Arc::clone(&processed_files);
        let base_dir = dir_path.to_path_buf();
        thread::spawn(move || {
            if let Err(e) = handle_event(event, processed, &base_dir) {
                eprintln!("Error: {}", e);
            }
        });
    }

    Ok(())
}

fn handle_event(
    event: Result<Event, notify::Error>,
    processed_files: Arc<Mutex<HashSet<PathBuf>>>,
    base_dir: &Path,
) -> Result<()> {
    let event = event?;
    if !(event.kind.is_create() || event.kind.is_modify()) {
        return Ok(());
    }

    for path in event.paths {
        if path.is_dir() {
            continue;
        }

        let mut processed = processed_files.lock().unwrap();
        if processed.contains(&path) {
            continue;
        }

        let ext = path
            .extension()
            .and_then(|e| e.to_str())
            .unwrap_or("no_extension");
        let target_dir = base_dir.join(ext);

        std::fs::create_dir_all(&target_dir)?;

        let file_name = path.file_name().context("Invalid filename")?;
        let target_path = target_dir.join(file_name);

        if let Err(e) = std::fs::rename(&path, &target_path) {
            eprintln!("Failed to move {}: {}", path.display(), e);
            continue;
        }

        processed.insert(path);
    }

    Ok(())
}
