use std::collections::HashMap;
use std::fs::File;
use std::path::PathBuf;
use std::sync::Mutex;
use serde::{Deserialize, Serialize};
use tokio::io::{AsyncBufReadExt, BufReader};

#[derive(Debug, Serialize, Deserialize, Clone)]
struct Inventory {
    stores: HashMap<String, Store>,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
struct Store {
    items: HashMap<String, i32>,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let json_path = PathBuf::from("inventory.json");
    let inventory = std::sync::Arc::new(Mutex::new(load_or_create_inventory(&json_path)?));

    let handle = tokio::spawn(process_input(inventory.clone(), json_path.clone()));
    handle.await?;
    Ok(())
}

fn load_or_create_inventory(path: &PathBuf) -> Result<Inventory, Box<dyn std::error::Error>> {
    if path.exists() {
        Ok(serde_json::from_reader(File::open(path)?)?)
    } else {
        Ok(Inventory { stores: HashMap::new() })
    }
}

async fn process_input(inventory: std::sync::Arc<Mutex<Inventory>>, json_path: PathBuf) {
    let stdin = BufReader::new(tokio::io::stdin());
    let mut lines = stdin.lines();

    while let Ok(Some(line)) = lines.next_line().await {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.is_empty() { continue; }

        match parts[0] {
            "update" if parts.len() == 4 => {
                let store = parts[1].to_string();
                let item = parts[2].to_string();
                let qty: i32 = match parts[3].parse() {
                    Ok(v) => v,
                    Err(_) => { println!("Invalid quantity"); continue; }
                };

                let mut inv = inventory.lock().unwrap();
                inv.stores.entry(store)
                    .or_insert(Store { items: HashMap::new() })
                    .items.insert(item, qty);

                let data = inv.clone();
                drop(inv);

                let path = json_path.clone();
                tokio::task::spawn_blocking(move || {
                    File::create(&path).and_then(|f| serde_json::to_writer_pretty(f, &data)).unwrap();
                }).await.unwrap();
            }
            "exit" => break,
            _ => println!("Invalid command"),
        }
    }
}
