use serde::Deserialize;
use std::env;
use std::fs::{File, OpenOptions};
use std::io::{Read, Seek, SeekFrom};
use std::sync::mpsc;
use std::thread;
use std::time::{Duration, Instant};

#[derive(Debug, Deserialize)]
struct LogEntry {
    status: String,
    response_time_ms: u64,
}

struct Metrics {
    total_requests: u64,
    total_errors: u64,
    total_response_time: u64,
    max_response_time: u64,
}

impl Metrics {
    fn new() -> Self {
        Metrics {
            total_requests: 0,
            total_errors: 0,
            total_response_time: 0,
            max_response_time: 0,
        }
    }

    fn update(&mut self, entry: &LogEntry) {
        self.total_requests += 1;
        if entry.status.starts_with('5') || entry.status == "error" {
            self.total_errors += 1;
        }
        self.total_response_time += entry.response_time_ms;
        self.max_response_time = self.max_response_time.max(entry.response_time_ms);
    }

    fn report(&self) -> (f64, f64, u64) {
        let error_rate = if self.total_requests > 0 {
            (self.total_errors as f64 / self.total_requests as f64) * 100.0
        } else {
            0.0
        };
        let avg_response = if self.total_requests > 0 {
            self.total_response_time as f64 / self.total_requests as f64
        } else {
            0.0
        };
        (error_rate, avg_response, self.max_response_time)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().skip(1).collect();
    if args.is_empty() {
        eprintln!("Usage: {} [LOG_FILES...]", env::args().next().unwrap());
        std::process::exit(1);
    }

    let (tx, rx) = mpsc::channel::<LogEntry>();
    let metrics = std::sync::Arc::new(std::sync::Mutex::new(Metrics::new()));

    let reporter_metrics = metrics.clone();
    thread::spawn(move || loop {
        thread::sleep(Duration::from_secs(5));
        let m = reporter_metrics.lock().unwrap();
        let (err, avg, max) = m.report();
        println!(
            "Error Rate: {:.2}%, Avg Response: {:.2}ms, Max Response: {}ms",
            err, avg, max
        );
    });

    for path in args {
        let sender = tx.clone();
        thread::spawn(move || -> Result<(), Box<dyn std::error::Error>> {
            let mut file = OpenOptions::new().read(true).open(&path)?;
            file.seek(SeekFrom::End(0))?;
            let mut last_pos = file.stream_position()?;
            let mut buffer = Vec::new();

            loop {
                let current_size = file.metadata()?.len();
                if current_size < last_pos {
                    file.seek(SeekFrom::Start(0))?;
                    last_pos = 0;
                    buffer.clear();
                }

                if current_size > last_pos {
                    let mut chunk = vec![0; (current_size - last_pos) as usize];
                    file.read_exact(&mut chunk)?;
                    buffer.extend_from_slice(&chunk);

                    let mut split = buffer.split_inclusive(|&c| c == b'\n');
                    buffer = split.next_back().unwrap_or(&[]).to_vec();

                    for line in split {
                        let entry: LogEntry = serde_json::from_slice(line)?;
                        sender.send(entry)?;
                    }

                    last_pos = current_size;
                }
                thread::sleep(Duration::from_millis(100));
            }
        });
    }

    let aggregator_metrics = metrics.clone();
    thread::spawn(move || {
        for entry in rx {
            let mut m = aggregator_metrics.lock().unwrap();
            m.update(&entry);
        }
    });

    loop {
        thread::sleep(Duration::from_secs(3600));
    }
}
