import com.sun.net.httpserver.*;
import java.io.*;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class SentimentAnalysisServer {
    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/sentiment", new SentimentHandler());
        server.start();
    }

    record SentimentRequest(String text) {}
    record SentimentResponse(String sentiment) {}

    static class SentimentHandler implements HttpHandler {
        private final static List<String> POSITIVE = List.of("happy", "good", "great", "excellent");
        private final static List<String> NEGATIVE = List.of("sad", "bad", "terrible", "awful");

        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!exchange.getRequestMethod().equals("POST")) {
                exchange.sendResponseHeaders(405, -1);
                return;
            }

            try (InputStream is = exchange.getRequestBody()) {
                String json = new String(is.readAllBytes(), StandardCharsets.UTF_8);
                String text = json.split("\"text\":\"")[1].split("\"")[0];
                String result = analyze(text.toLowerCase());

                String response = STR."{\"sentiment\":\"\{result}\"}";
                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.length());
                OutputStream os = exchange.getResponseBody();
                os.write(response.getBytes());
                os.close();
            } catch (Exception e) {
                exchange.sendResponseHeaders(400, -1);
            }
        }

        private String analyze(String text) {
            int positive = (int) POSITIVE.stream().filter(text::contains).count();
            int negative = (int) NEGATIVE.stream().filter(text::contains).count();
            return positive > negative ? "positive" : negative > positive ? "negative" : "neutral";
        }
    }
}
