use chrono::{DateTime, Utc};
use futures::{SinkExt, StreamExt};
use serde::{Deserialize, Serialize};
use std::{collections::HashMap, error::Error, sync::Arc};
use tokio::{
    net::{TcpListener, TcpStream},
    sync::{mpsc, Mutex},
};
use tokio_tungstenite::{tungstenite::Message, WebSocketStream};

#[derive(Serialize, Deserialize)]
struct ChatMessage {
    sender: String,
    recipient: String,
    content: String,
    timestamp: DateTime<Utc>,
}

#[derive(Deserialize)]
struct IncomingMessage {
    recipient: String,
    content: String,
}

struct SharedState {
    clients: Mutex<HashMap<String, mpsc::UnboundedSender<Message>>>,
    log_file: Mutex<tokio::fs::File>,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    let log_file = tokio::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open("chat.log")
        .await?;
    let state = Arc::new(SharedState {
        clients: Mutex::new(HashMap::new()),
        log_file: Mutex::new(log_file),
    });

    loop {
        let (stream, _) = listener.accept().await?;
        let state_clone = state.clone();
        tokio::spawn(async move {
            if let Err(e) = handle_client(stream, state_clone).await {
                eprintln!("Client error: {}", e);
            }
        });
    }
}

async fn handle_client(
    stream: TcpStream,
    state: Arc<SharedState>,
) -> Result<(), Box<dyn Error>> {
    let ws_stream = tokio_tungstenite::accept_async(stream).await?;
    let (mut ws_tx, mut ws_rx) = ws_stream.split();

    let username = match ws_rx.next().await {
        Some(Ok(msg)) => msg.to_text()?.trim().to_string(),
        _ => return Err("Invalid username".into()),
    };

    let (sender, mut receiver) = mpsc::unbounded_channel();
    {
        let mut clients = state.clients.lock().await;
        if clients.contains_key(&username) {
            ws_tx.send(Message::Text("Username taken".into())).await?;
            return Ok(());
        }
        clients.insert(username.clone(), sender);
    }

    ws_tx.send(Message::Text("Connected".into())).await?;

    let send_task = tokio::spawn(async move {
        while let Some(msg) = receiver.recv().await {
            if ws_tx.send(msg).await.is_err() {
                break;
            }
        }
    });

    while let Some(Ok(msg)) = ws_rx.next().await {
        if let Ok(incoming) = serde_json::from_str::<IncomingMessage>(msg.to_text()?) {
            let chat_msg = ChatMessage {
                sender: username.clone(),
                recipient: incoming.recipient,
                content: incoming.content,
                timestamp: Utc::now(),
            };
            let json_msg = serde_json::to_string(&chat_msg)?;

            {
                let mut file = state.log_file.lock().await;
                file.write_all(json_msg.as_bytes()).await?;
                file.write_all(b"\n").await?;
            }

            let mut clients = state.clients.lock().await;
            match clients.get(&chat_msg.recipient) {
                Some(tx) => tx.send(Message::Text(json_msg))?,
                None => {
                    ws_tx.send(Message::Text(format!("User {} offline", chat_msg.recipient)))
                        .await?;
                }
            }
        }
    }

    send_task.abort();
    state.clients.lock().await.remove(&username);
    Ok(())
}
