import java.time.*;
import java.util.*;
import java.util.concurrent.*;
import java.sql.*;

public interface Database {
    void connect() throws Exception;
    void deleteRecordsBefore(String table, String column, Temporal cutoff) throws Exception;
}

public class SqlDatabase implements Database {
    private Connection connection;

    public SqlDatabase(String url, String user, String password) throws SQLException {
        connection = DriverManager.getConnection(url, user, password);
    }

    @Override
    public void connect() { /* Established in constructor */ }

    @Override
    public void deleteRecordsBefore(String table, String column, Temporal cutoff) throws SQLException {
        String sql = String.format("DELETE FROM %s WHERE %s < ?", table, column);
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.setObject(1, cutoff);
            stmt.executeUpdate();
        }
    }
}

public class NoSqlDatabase implements Database {
    @Override
    public void connect() { /* NoSQL connection logic */ }

    @Override
    public void deleteRecordsBefore(String table, String column, Temporal cutoff) {
        /* NoSQL-specific deletion logic */
    }
}

public record RetentionPolicy(String columnName, String columnType, int durationDays) {}

public class DataRetentionConfig {
    private final Map<String, RetentionPolicy> policies = new HashMap<>();

    public void addPolicy(String tableName, RetentionPolicy policy) {
        policies.put(tableName, policy);
    }

    public Map<String, RetentionPolicy> getPolicies() {
        return Collections.unmodifiableMap(policies);
    }
}

public class DataRetentionService {
    private final DataRetentionConfig config;
    private final Database database;

    public DataRetentionService(DataRetentionConfig config, Database database) {
        this.config = config;
        this.database = database;
    }

    public void purgeData() throws Exception {
        for (Map.Entry<String, RetentionPolicy> entry : config.getPolicies().entrySet()) {
            String table = entry.getKey();
            RetentionPolicy policy = entry.getValue();

            Temporal cutoff = switch (policy.columnType()) {
                case "DATE" -> LocalDate.now().minusDays(policy.durationDays());
                case "TIMESTAMP" -> LocalDateTime.now().minusDays(policy.durationDays());
                default -> throw new IllegalArgumentException("Unsupported column type");
            };

            database.deleteRecordsBefore(table, policy.columnName(), cutoff);
        }
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        DataRetentionConfig config = new DataRetentionConfig();
        config.addPolicy("user_logs", new RetentionPolicy("created_at", "TIMESTAMP", 365));
        config.addPolicy("temporary_data", new RetentionPolicy("expiration_date", "DATE", 30));

        Database database = args.length > 0 && args[0].equals("nosql") 
            ? new NoSqlDatabase() 
            : new SqlDatabase("jdbc:mysql://localhost:3306/db", "user", "pass");

        DataRetentionService service = new DataRetentionService(config, database);
        ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor();
        scheduler.scheduleAtFixedRate(() -> {
            try {
                service.purgeData();
            } catch (Exception e) {
                e.printStackTrace();
            }
        }, 0, 1, TimeUnit.DAYS);
    }
}
