    let logs = tokio::task::spawn_blocking(move || serde_json::from_str::<Vec<LogEntry>>(&contents)).await??;
    let bin_data = tokio::task::spawn_blocking(move || bincode::serialize(&logs)).await??;
    fs::write(path.with_extension("bin"), bin_data).await?;
