// StockFetcher.java
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.ArrayList;
import java.util.List;
import java.util.logging.Logger;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

public class StockFetcher {
    private static final Logger logger = Logger.getLogger(StockFetcher.class.getName());
    private static final String API_URL = "https://api.example.com/stocks?symbol=%s";

    public String fetchStockData(String symbol) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(String.format(API_URL, symbol)))
                .build();
        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        logger.info("Fetched stock data for symbol: " + symbol);
        return response.body();
    }

    public List<StockData> parseResponse(String jsonResponse) throws IOException {
        ObjectMapper mapper = new ObjectMapper();
        JsonNode rootNode = mapper.readTree(jsonResponse);
        List<StockData> dataList = new ArrayList<>();
        JsonNode timeSeries = rootNode.path("Time Series (5min)");
        timeSeries.fields().forEachRemaining(entry -> {
            String timestamp = entry.getKey();
            double price = entry.getValue().path("4. close").asDouble();
            dataList.add(new StockData(timestamp, price));
        });
        logger.info("Parsed " + dataList.size() + " stock data entries");
        return dataList;
    }
}

