// StockProcessor.java
import java.util.List;
import java.util.logging.Logger;

public class StockProcessor {
    private static final Logger logger = Logger.getLogger(StockProcessor.class.getName());

    public StockStats calculateStats(List<StockData> data) {
        if (data.isEmpty()) throw new IllegalArgumentException("No data provided");

        double max = data.get(0).getPrice();
        double min = data.get(0).getPrice();
        double sum = 0;

        for (StockData d : data) {
            double price = d.getPrice();
            if (price > max) max = price;
            if (price < min) min = price;
            sum += price;
        }

        StockStats stats = new StockStats(
            sum / data.size(),
            max,
            min,
            data.get(0).getTimestamp(),
            data.get(data.size()-1).getTimestamp()
        );
        logger.info("Calculated stats: " + stats);
        return stats;
    }
}

