import java.sql.*;
import java.util.logging.Logger;

public class StockRepository {
    private static final Logger logger = Logger.getLogger(StockRepository.class.getName());
    private static final String DB_URL = "jdbc:sqlite:stock_data.db";

    public StockRepository() {
        createTable();
    }

    private void createTable() {
        String sql = "CREATE TABLE IF NOT EXISTS stock_stats (" +
                     "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                     "average_price REAL NOT NULL," +
                     "max_price REAL NOT NULL," +
                     "min_price REAL NOT NULL," +
                     "start_time TEXT NOT NULL," +
                     "end_time TEXT NOT NULL," +
                     "calculation_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP)";
        try (Connection conn = DriverManager.getConnection(DB_URL);
             Statement stmt = conn.createStatement()) {
            stmt.execute(sql);
            logger.info("Database table created/verified");
        } catch (SQLException e) {
            logger.severe("Error creating table: " + e.getMessage());
        }
    }

    public void saveStats(StockStats stats) {
        String sql = "INSERT INTO stock_stats (average_price, max_price, min_price, start_time, end_time) VALUES (?, ?, ?, ?, ?)";
        try (Connection conn = DriverManager.getConnection(DB_URL);
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setDouble(1, stats.getAveragePrice());
            pstmt.setDouble(2, stats.getMaxPrice());
            pstmt.setDouble(3, stats.getMinPrice());
            pstmt.setString(4, stats.getStartTime());
            pstmt.setString(5, stats.getEndTime());
            pstmt.executeUpdate();
            logger.info("Saved stats to database");
        } catch (SQLException e) {
            logger.severe("Error saving stats: " + e.getMessage());
        }
    }
}
