use std::collections::VecDeque;
use std::error::Error;
use std::io;
use csv::{Reader, ErrorKind};
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct StockEntry {
    price: f64,
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut reader = Reader::from_reader(io::stdin());
    let mut window = VecDeque::with_capacity(10);
    let mut sum = 0.0;

    for result in reader.deserialize() {
        let record: StockEntry = match result {
            Ok(r) => r,
            Err(e) => match e.kind() {
                ErrorKind::Deserialize { .. } => {
                    eprintln!("CSV parse error: {}", e);
                    continue;
                }
                _ => return Err(e.into()),
            },
        };

        let price = record.price;
        window.push_back(price);
        sum += price;

        if window.len() > 10 {
            let oldest = window.pop_front().unwrap();
            sum -= oldest;
        }

        if window.len() >= 10 {
            println!("{:.2}", sum / 10.0);
        }
    }

    Ok(())
}
