import java.nio.file.*;
import java.util.*;
import java.io.*;
import java.util.stream.*;

public class CSVProcessor {
    public static void main(String[] args) {
        Map<String, String> argsMap = new HashMap<>();
        for (int i = 0; i < args.length; i++) {
            switch (args[i]) {
                case "-i": argsMap.put("input", args[++i]); break;
                case "-o": argsMap.put("output", args[++i]); break;
                case "-c": argsMap.put("config", args[++i]); break;
                case "-ops": argsMap.put("operations", args[++i]); break;
            }
        }
        List<String> columnOrder = readConfig(argsMap.get("config"));
        processCSV(argsMap.get("input"), argsMap.get("output"), columnOrder, argsMap.get("operations"));
    }

    private static List<String> readConfig(String configPath) {
        try {
            return Files.readAllLines(Paths.get(configPath));
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }

    private static void processCSV(String inputPath, String outputPath, List<String> columnOrder, String operations) {
        Set<String> seenRows = new HashSet<>();
        List<String> opList = Arrays.asList(operations.split(","));
        try (BufferedReader reader = Files.newBufferedReader(Paths.get(inputPath));
             BufferedWriter writer = Files.newBufferedWriter(Paths.get(outputPath))) {
            String headerLine = reader.readLine();
            if (headerLine == null) return;
            List<String> headers = Arrays.asList(headerLine.split(","));
            Map<String, Integer> headerIndices = new HashMap<>();
            for (int i = 0; i < headers.size(); i++) headerIndices.put(headers.get(i), i);
            List<Integer> newIndices = columnOrder.stream()
                .map((var header) -> headerIndices.get(header))
                .collect(Collectors.toList());
            writer.write(String.join(",", columnOrder) + "\n");
            String line;
            while ((line = reader.readLine()) != null) {
                List<String> row = Arrays.asList(line.split(","));
                if (opList.contains("consistency") && row.size() != headers.size()) continue;
                if (opList.contains("removeDuplicates")) {
                    String rowKey = String.join(",", row);
                    if (seenRows.contains(rowKey)) continue;
                    seenRows.add(rowKey);
                }
                List<String> newRow = newIndices.stream()
                    .map((var index) -> row.get(index))
                    .collect(Collectors.toList());
                writer.write(String.join(",", newRow) + "\n");
            }
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }
}
