use http_body_util::{Empty, Full};
use hyper::body::Bytes;
use hyper::server::conn::http1;
use hyper::service::service_fn;
use hyper::{Method, Request, Response, StatusCode};
use hyper_util::rt::TokioIo;
use mime_guess::from_path;
use percent_encoding::percent_decode_str;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::fs::File;
use tokio::net::TcpListener;
use tokio_util::io::ReaderStream;

async fn serve_file(base_path: Arc<PathBuf>, req: Request<hyper::body::Incoming>) -> Result<Response<Full<Bytes>>, hyper::Error> {
    if req.method() != Method::GET {
        return Ok(Response::builder()
            .status(StatusCode::METHOD_NOT_ALLOWED)
            .body(Full::default())
            .unwrap());
    }

    let path = percent_decode_str(req.uri().path()).decode_utf8_lossy();
    let mut requested_path = Path::new(&*path).to_path_buf();

    if requested_path.starts_with("/") {
        requested_path = requested_path.strip_prefix("/").unwrap().to_path_buf();
    }

    let full_path = base_path.join(requested_path).canonicalize().map_err(|_| {
        hyper::Error::new(std::io::Error::new(
            std::io::ErrorKind::NotFound,
            "File not found",
        ))
    })?;

    if !full_path.starts_with(&*base_path) {
        return Ok(Response::builder()
            .status(StatusCode::NOT_FOUND)
            .body(Full::default())
            .unwrap());
    }

    let file = File::open(&full_path).await.map_err(|e| {
        hyper::Error::new(std::io::Error::new(
            e.kind(),
            format!("File error: {}", e),
        ))
    })?;

    let mime_type = from_path(&full_path).first_or_octet_stream().to_string();
    let stream = ReaderStream::new(file);
    let body = stream.map_ok(|chunk| chunk).map_err(|e| {
        hyper::Error::new(std::io::Error::new(
            std::io::ErrorKind::Other,
            format!("IO error: {}", e),
        ))
    });

    Ok(Response::builder()
        .header(hyper::header::CONTENT_TYPE, mime_type)
        .body(Full::new(Bytes::from_iter(body)))
        .unwrap())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let base_path = Arc::new(std::env::current_dir()?.join("static"));
    let listener = TcpListener::bind("127.0.0.1:8080").await?;

    loop {
        let (stream, _) = listener.accept().await?;
        let io = TokioIo::new(stream);
        let base_path = base_path.clone();

        tokio::task::spawn(async move {
            let service = service_fn(move |req| serve_file(base_path.clone(), req));
            if let Err(err) = http1::Builder::new().serve_connection(io, service).await {
                eprintln!("Connection error: {:?}", err);
            }
        });
    }
}
