use config::Config;
use notify::{Config as NotifyConfig, EventKind, RecommendedWatcher, Watcher};
use serde::Deserialize;
use std::path::Path;
use std::time::SystemTime;
use tokio::sync::mpsc;

#[derive(Debug, Deserialize)]
struct Settings {
    watch_dirs: Vec<String>,
    smtp_server: String,
    smtp_port: u16,
    smtp_username: String,
    smtp_password: String,
    email_from: String,
    email_to: String,
}

async fn send_email(settings: &Settings, file_path: &str, detected_time: &str) {
    use lettre::transport::smtp::authentication::Credentials;
    use lettre::{Message, AsyncTransport, Tokio1Executor};

    let email = Message::builder()
        .from(settings.email_from.parse().unwrap())
        .to(settings.email_to.parse().unwrap())
        .subject("New File Detected")
        .body(format!(
            "New file created:\nName: {}\nPath: {}\nDetected: {}",
            Path::new(file_path).file_name().unwrap().to_str().unwrap(),
            file_path,
            detected_time
        ))
        .unwrap();

    let creds = Credentials::new(
        settings.smtp_username.clone(),
        settings.smtp_password.clone(),
    );

    let mailer = lettre::AsyncSmtpTransport::<Tokio1Executor>::relay(&settings.smtp_server)
        .unwrap()
        .port(settings.smtp_port)
        .credentials(creds)
        .build();

    if let Err(e) = mailer.send(email).await {
        eprintln!("Error sending email: {}", e);
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let settings = Config::builder()
        .add_source(config::File::with_name("config"))
        .build()?
        .try_deserialize::<Settings>()?;

    let (tx, mut rx) = mpsc::channel(100);

    for dir in &settings.watch_dirs {
        let dir = dir.clone();
        let tx = tx.clone();

        tokio::spawn(async move {
            let (mut watcher, mut rx) = RecommendedWatcher::new(
                move |res| {
                    futures::executor::block_on(async {
                        tx.send(res).await.unwrap();
                    })
                },
                NotifyConfig::default().with_poll_interval(std::time::Duration::from_millis(100)),
            )
            .unwrap();

            watcher.watch(Path::new(&dir), notify::RecursiveMode::NonRecursive).unwrap();

            while let Some(res) = rx.recv().await {
                if let Ok(event) = res {
                    if let EventKind::Create(_) = event.kind {
                        for path in event.paths {
                            if path.is_file() {
                                let detected_time = chrono::Local::now().to_rfc3339();
                                let path_str = path.to_str().unwrap();
                                send_email(&settings, path_str, &detected_time).await;
                            }
                        }
                    }
                }
            }
        });
    }

    Ok(())
}
