use anyhow::Result;
use chrono::Utc;
use csv::WriterBuilder;
use sysinfo::{CpuExt, DiskExt, System, SystemExt};
use tokio::{
    fs::OpenOptions,
    time::{interval, Duration},
};

#[tokio::main]
async fn main() -> Result<()> {
    let mut interval = interval(Duration::from_secs(60));
    loop {
        interval.tick().await;

        let timestamp = Utc::now().to_rfc3339();
        let mut system = System::new();
        system.refresh_cpu();
        system.refresh_memory();
        system.refresh_disks();

        let cpu_usage = system.global_cpu_info().cpu_usage();
        let used_memory = system.used_memory();
        let total_memory = system.total_memory();

        let disks = system.disks();
        let root_disk = disks
            .iter()
            .find(|d| d.mount_point() == std::path::Path::new("/"))
            .ok_or(anyhow::anyhow!("Root disk not found"))?;
        let total_disk = root_disk.total_space();
        let used_disk = total_disk - root_disk.available_space();

        let file = OpenOptions::new()
            .append(true)
            .create(true)
            .open("resources.csv")
            .await?;
        let metadata = file.metadata().await?;
        let is_empty = metadata.len() == 0;

        let mut writer = WriterBuilder::new()
            .has_headers(false)
            .from_writer(file);

        if is_empty {
            writer.write_record(&["timestamp", "cpu_usage", "used_memory", "total_memory", "used_disk", "total_disk"])?;
        }

        writer.write_record(&[
            &timestamp,
            &cpu_usage.to_string(),
            &used_memory.to_string(),
            &total_memory.to_string(),
            &used_disk.to_string(),
            &total_disk.to_string(),
        ])?;
        writer.flush()?;
    }
}
