import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;

import java.io.IOException;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import java.net.URI;
import java.util.concurrent.Executors;
import java.util.concurrent.Executor;
import javax.management.MBeanServerConnection;
import javax.management.remote.JMXConnector;
import javax.management.remote.JMXServiceURL;
import javax.management.ObjectName;
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import com.sun.tools.attach.VirtualMachine;
import java.util.HashMap;
import java.util.Map;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;

public class MonitorTool {
    private static final int SERVER_PORT = 8080;
    private static final int THREAD_POOL_SIZE = 10;

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(SERVER_PORT), 0);
        server.createContext("/stats", new StatsHandler());
        Executor executor = Executors.newFixedThreadPool(THREAD_POOL_SIZE);
        server.setExecutor(executor);
        server.start();
        System.out.println("Server started on port " + SERVER_PORT);
    }

    static class StatsHandler implements HttpHandler {
        private final HttpClient httpClient = HttpClient.newHttpClient();

        @Override
        public void handle(HttpExchange exchange) throws IOException {
            try {
                URI uri = exchange.getRequestURI();
                String query = uri.getQuery();
                String pid = query.split("=")[1];

                Map<String, Object> metrics = getMetrics(pid);
                String response = toJson(metrics);
                exchange.sendResponseHeaders(200, response.getBytes().length);
                OutputStream os = exchange.getResponseBody();
                os.write(response.getBytes());
                os.close();

                httpClient.send(HttpRequest.newBuilder()
                        .uri(URI.create("http://localhost:" + SERVER_PORT + "/stats?pid=" + pid))
                        .GET().build(), HttpResponse.BodyHandlers.discarding());
            } catch (Exception e) {
                e.printStackTrace();
                String error = "{\"error\":\"" + e.getMessage() + "\"}";
                exchange.sendResponseHeaders(500, error.getBytes().length);
                OutputStream os = exchange.getResponseBody();
                os.write(error.getBytes());
                os.close();
            }
        }

        private Map<String, Object> getMetrics(String pid) throws Exception {
            VirtualMachine vm = VirtualMachine.attach(pid);
            String connectorAddress = vm.getAgentProperties().getProperty("com.sun.management.jmxremote.localConnectorAddress");
            if (connectorAddress == null) {
                connectorAddress = vm.startLocalManagementAgent();
            }
            JMXServiceURL url = new JMXServiceURL(connectorAddress);
            JMXConnector jmxConnector = javax.management.remote.JMXConnectorFactory.connect(url);
            MBeanServerConnection connection = jmxConnector.getMBeanServerConnection();

            MemoryMXBean memoryBean = ManagementFactory.newPlatformMXBeanProxy(
                    connection, ManagementFactory.MEMORY_MXBEAN_NAME, MemoryMXBean.class);
            ObjectName osName = new ObjectName("java.lang:type=OperatingSystem");
            double cpuUsage = (Double) connection.getAttribute(osName, "ProcessCpuLoad");

            long used = memoryBean.getHeapMemoryUsage().getUsed();
            long max = memoryBean.getHeapMemoryUsage().getMax();
            long available = max - used;

            Map<String, Object> metrics = new HashMap<>();
            metrics.put("totalMemoryUsed", used);
            metrics.put("memoryAvailable", available);
            metrics.put("cpuUtilizationPercentage", cpuUsage * 100);
            jmxConnector.close();
            vm.detach();
            return metrics;
        }

        private String toJson(Map<String, Object> metrics) {
            return String.format("{\"totalMemoryUsed\":%d,\"memoryAvailable\":%d,\"cpuUtilizationPercentage\":%.2f}",
                    metrics.get("totalMemoryUsed"), metrics.get("memoryAvailable"), metrics.get("cpuUtilizationPercentage"));
        }
    }
}
