    private static final DateTimeFormatter TIMESTAMP_FORMAT = DateTimeFormatter.ISO_INSTANT;

    public static void main(String[] args) throws Exception {
        String configUrl = args.length > 0 ? args[0] : "http://config-server.example/settings";
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

        scheduler.scheduleAtFixedRate(new ConfigFetcher(configUrl), 0, 1, TimeUnit.MINUTES);
        scheduler.scheduleAtFixedRate(new ResourceChecker(), 5, 5, TimeUnit.SECONDS);

        Runtime.getRuntime().addShutdownHook(new Thread(scheduler::shutdown));
    }

    private static class Config {
        final int cpuThreshold;
        final int memoryThreshold;

        Config(int cpuThreshold, int memoryThreshold) {
            this.cpuThreshold = cpuThreshold;
            this.memoryThreshold = memoryThreshold;
        }
    }

    private static class ConfigFetcher implements Runnable {
        private final String url;
        private final HttpClient httpClient = HttpClient.newHttpClient();

        ConfigFetcher(String url) {
            this.url = url;
        }

        @Override
        public void run() {
            try {
                HttpRequest request = HttpRequest.newBuilder().uri(URI.create(url)).build();
                String response = httpClient.send(request, HttpResponse.BodyHandlers.ofString()).body();
                String[] parts = response.split(",");
                int cpu = Integer.parseInt(parts[0].split(":")[1]);
                int mem = Integer.parseInt(parts[1].split(":")[1]);
                CONFIG.set(new Config(cpu, mem));
            } catch (Exception e) {
                System.err.println("Config fetch error: " + e.getMessage());
            }
        }
    }

    private static class ResourceChecker implements Runnable {
        private final SystemInfo systemInfo = new SystemInfo();
        private final HardwareAbstractionLayer hardware = systemInfo.getHardware();

        @Override
        public void run() {
            Config config = CONFIG.get();
            double cpuLoad = hardware.getProcessor().getSystemCpuLoad(1000)[0] * 100;
            long memTotal = hardware.getMemory().getTotal();
            long memAvailable = hardware.getMemory().getAvailable();
            double memUsage = ((memTotal - memAvailable) * 100.0) / memTotal;

            if (cpuLoad > config.cpuThreshold) {
                logAlert("CPU", cpuLoad);
            }
            if (memUsage > config.memoryThreshold) {
                logAlert("Memory", memUsage);
            }
        }

        private void logAlert(String resource, double utilization) {
            String logEntry = String.format(
                "{\"timestamp\":\"%s\",\"resource\":\"%s\",\"utilization\":%.2f}%n",
                TIMESTAMP_FORMAT.format(Instant.now()), resource, utilization
            );
            try {
                Files.writeString(Path.of("alerts.json"), logEntry, StandardOpenOption.CREATE, StandardOpenOption.APPEND);
            } catch (Exception e) {
                System.err.println("Log error: " + e.getMessage());
            }
        }
    }
}
