import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.stream.Collectors;
import java.sql.*;
import com.google.gson.Gson;
import com.google.gson.reflect.TypeToken;

public class AnalyticsEngine {
    private static final String API_URL = "https://api.example.com/transactions";
    private static final String DB_URL = "jdbc:sqlite:analytics.db";
    private final HttpClient httpClient = HttpClient.newHttpClient();
    private final Gson gson = new Gson();

    public static class Transaction {
        public double amount;
        public long timestamp;
    }

    public CompletableFuture<Void> processData() {
        return CompletableFuture.supplyAsync(() -> fetchTransactions())
                .thenApply(this::aggregateData)
                .thenAccept(this::storeResults);
    }

    private List<Transaction> fetchTransactions() {
        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(API_URL))
                    .GET()
                    .build();
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            return gson.fromJson(response.body(), new TypeToken<List<Transaction>>(){}.getType());
        } catch (Exception e) {
            throw new RuntimeException("API request failed", e);
        }
    }

    private AggregationResult aggregateData(List<Transaction> transactions) {
        double sum = transactions.stream().mapToDouble(t -> t.amount).sum();
        double avg = transactions.stream().mapToDouble(t -> t.amount).average().orElse(0);
        double max = transactions.stream().mapToDouble(t -> t.amount).max().orElse(0);
        return new AggregationResult(sum, avg, max);
    }

    private void storeResults(AggregationResult result) {
        String sql = "INSERT INTO aggregations (sum, avg, max) VALUES (?, ?, ?)";
        try (Connection conn = DriverManager.getConnection(DB_URL);
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setDouble(1, result.sum);
            pstmt.setDouble(2, result.avg);
            pstmt.setDouble(3, result.max);
            pstmt.executeUpdate();
        } catch (SQLException e) {
            throw new RuntimeException("Database operation failed", e);
        }
    }

    public static void main(String[] args) throws Exception {
        Class.forName("org.sqlite.JDBC");
        try (Connection conn = DriverManager.getConnection(DB_URL);
             Statement stmt = conn.createStatement()) {
            stmt.execute("CREATE TABLE IF NOT EXISTS aggregations (id INTEGER PRIMARY KEY AUTOINCREMENT, sum REAL, avg REAL, max REAL, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP)");
        }
        new AnalyticsEngine().processData().join();
    }

    private static class AggregationResult {
        final double sum;
        final double avg;
        final double max;

        AggregationResult(double sum, double avg, double max) {
            this.sum = sum;
            this.avg = avg;
            this.max = max;
        }
    }
}
