import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.nio.file.*;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import net.sourceforge.tess4j.*;

public class ImageOCRMonitor {
    private static final Logger logger = LoggerFactory.getLogger(ImageOCRMonitor.class);
    private static final String[] IMAGE_EXTENSIONS = new String[]{"png", "jpg", "jpeg", "bmp", "gif"};
    private final ExecutorService executor = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());
    private final Path dir;
    private final Tesseract tesseract;

    public ImageOCRMonitor(Path dir) {
        this.dir = dir;
        tesseract = new Tesseract();
        tesseract.setDatapath("tessdata");
        tesseract.setLanguage("eng");
    }

    public void start() throws IOException {
        WatchService watchService = FileSystems.getDefault().newWatchService();
        dir.register(watchService, StandardWatchEventKinds.ENTRY_CREATE);

        logger.info("Starting directory monitor for {}", dir);
        new Thread(() -> {
            try {
                while (true) {
                    WatchKey key = watchService.take();
                    for (WatchEvent<?> event : key.pollEvents()) {
                        if (event.kind() == StandardWatchEventKinds.ENTRY_CREATE) {
                            Path file = dir.resolve((Path) event.context());
                            executor.submit(() -> processFile(file));
                        }
                    }
                    key.reset();
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }).start();
    }

    private void processFile(Path file) {
        try {
            if (isImageFile(file)) {
                logger.info("Processing new image: {}", file);
                BufferedImage image = ImageIO.read(file.toFile());
                String text = tesseract.doOCR(image);
                saveText(file, text);
                logger.info("OCR completed for {}", file);
            }
        } catch (Exception e) {
            logger.error("Error processing {}: {}", file, e.getMessage());
        }
    }

    private boolean isImageFile(Path file) {
        String fileName = file.getFileName().toString().toLowerCase();
        for (String ext : IMAGE_EXTENSIONS) {
            if (fileName.endsWith("." + ext)) {
                return true;
            }
        }
        return false;
    }

    private void saveText(Path imageFile, String text) throws IOException {
        String txtFileName = imageFile.getFileName().toString().replaceFirst("[.][^.]+$", "") + ".txt";
        Files.write(dir.resolve(txtFileName), text.getBytes(), StandardOpenOption.CREATE);
    }

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java ImageOCRMonitor <directory>");
            System.exit(1);
        }
        new ImageOCRMonitor(Path.of(args[0])).start();
    }
}
