import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.List;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.function.Function;

public sealed interface StockType permits CommonStock, PreferredStock {}
final class CommonStock implements StockType {}
final class PreferredStock implements StockType {}

record Stock(String symbol, double price, StockType type) {}

sealed abstract class MarketScenario permits BullMarket, BearMarket, MarketCrash {
    protected final transient Market market;
    protected final transient NotificationService notifier;

    public MarketScenario(Market market, NotificationService notifier) {
        this.market = market;
        this.notifier = notifier;
    }

    abstract void simulate();
}

final class BullMarket extends MarketScenario {
    public BullMarket(Market market, NotificationService notifier) {
        super(market, notifier);
    }

    @Override
    void simulate() {
        market.updateStocks(s -> new Stock(s.symbol(), s.price() * 1.05, s.type()));
        notifier.sendUpdate("BULL: Market rising - " + market.calculateIndex());
    }
}

final class BearMarket extends MarketScenario {
    public BearMarket(Market market, NotificationService notifier) {
        super(market, notifier);
    }

    @Override
    void simulate() {
        market.updateStocks(s -> new Stock(s.symbol(), s.price() * 0.97, s.type()));
        notifier.sendUpdate("BEAR: Market declining - " + market.calculateIndex());
    }
}

final class MarketCrash extends MarketScenario {
    public MarketCrash(Market market, NotificationService notifier) {
        super(market, notifier);
    }

    @Override
    void simulate() {
        market.updateStocks(s -> new Stock(s.symbol(), s.price() * 0.6, s.type()));
        notifier.sendUpdate("CRASH: Market collapse - " + market.calculateIndex());
    }
}

class Market {
    private final List<Stock> stocks = new CopyOnWriteArrayList<>();

    public Market(List<Stock> initialStocks) {
        stocks.addAll(initialStocks);
    }

    void updateStocks(Function<Stock, Stock> updateFunction) {
        stocks.replaceAll(updateFunction::apply);
    }

    double calculateIndex() {
        return stocks.stream().mapToDouble(Stock::price).average().orElse(0.0);
    }
}

class NotificationService {
    private static final HttpClient CLIENT = HttpClient.newHttpClient();
    private static final URI ENDPOINT = URI.create("http://market-events.example.com");

    void sendUpdate(String message) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(ENDPOINT)
                .POST(HttpRequest.BodyPublishers.ofString(message))
                .build();
        CLIENT.sendAsync(request, HttpResponse.BodyHandlers.discarding());
    }
}

public class StockMarketSimulation {
    public static void main(String[] args) {
        List<Stock> stocks = List.of(
                new Stock("JCOM", 45.80, new CommonStock()),
                new Stock("XTX", 1200.50, new PreferredStock())
        );

        Market market = new Market(stocks);
        NotificationService notifier = new NotificationService();
        ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();

        executor.submit(() -> new BullMarket(market, notifier).simulate());
        executor.submit(() -> new BearMarket(market, notifier).simulate());
        executor.submit(() -> new MarketCrash(market, notifier).simulate());

        executor.close();
    }
}
