import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;
import java.net.InetSocketAddress;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.io.IOException;
import java.io.OutputStream;
import javax.script.ScriptEngineManager;
import javax.script.ScriptEngine;

public class CurrencyConverter {

    private static final String API_URL = "https://api.exchangerate-api.com/v4/latest/";
    private static final long CACHE_DURATION_MS = 600000;

    private static class CachedRates {
        long timestamp;
        Map<String, Double> rates;
    }

    private static final Map<String, CachedRates> cache = new ConcurrentHashMap<>();

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/convert", new ConversionHandler());
        server.setExecutor(null);
        server.start();
    }

    static class ConversionHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            URI requestUri = exchange.getRequestURI();
            String query = requestUri.getQuery();
            Map<String, String> params = parseQuery(query);

            double amount = Double.parseDouble(params.get("amount"));
            String from = params.get("from").toUpperCase();
            String to = params.get("to").toUpperCase();

            try {
                Map<String, Double> rates = getExchangeRates(from);
                double rate = rates.getOrDefault(to, -1.0);
                if (rate <= 0) {
                    sendError(exchange, 400, "Invalid currency code");
                    return;
                }
                double converted = amount * rate;
                String response = String.format("{\"convertedAmount\": %.2f}", converted);
                sendResponse(exchange, 200, response);
            } catch (Exception e) {
                sendError(exchange, 500, "Internal server error");
            }
        }

        private Map<String, String> parseQuery(String query) {
            Map<String, String> params = new HashMap<>();
            for (String param : query.split("&")) {
                String[] pair = param.split("=");
                params.put(pair[0], pair[1]);
            }
            return params;
        }

        private Map<String, Double> getExchangeRates(String base) throws Exception {
            CachedRates cached = cache.get(base);
            if (cached != null && (System.currentTimeMillis() - cached.timestamp) < CACHE_DURATION_MS) {
                return cached.rates;
            }

            HttpClient client = HttpClient.newHttpClient();
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(API_URL + base))
                    .build();
            HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

            ScriptEngine engine = new ScriptEngineManager().getEngineByName("nashorn");
            Object parsed = engine.eval("Java.asJSONCompatible(" + response.body() + ")");
            Map<String, Object> data = (Map<String, Object>) parsed;
            Map<String, Double> rates = (Map<String, Double>) data.get("rates");

            CachedRates newCache = new CachedRates();
            newCache.timestamp = System.currentTimeMillis();
            newCache.rates = rates;
            cache.put(base, newCache);
            return rates;
        }

        private void sendResponse(HttpExchange exchange, int code, String response) throws IOException {
            exchange.getResponseHeaders().add("Content-Type", "application/json");
            exchange.sendResponseHeaders(code, response.getBytes().length);
            OutputStream os = exchange.getResponseBody();
            os.write(response.getBytes());
            os.close();
        }

        private void sendError(HttpExchange exchange, int code, String message) throws IOException {
            String response = String.format("{\"error\":\"%s\"}", message);
            sendResponse(exchange, code, response);
        }
    }
}
