import com.sun.net.httpserver.HttpServer;
import java.io.IOException;
import java.lang.management.ManagementFactory;
import java.lang.management.OperatingSystemMXBean;
import java.net.InetSocketAddress;
import java.time.Instant;
import java.util.concurrent.*;

public class HealthMonitorService {
    private static final ConcurrentHashMap<String, HealthMetrics> cache = new ConcurrentHashMap<>();
    private static final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public static void main(String[] args) throws IOException {
        startHealthMonitoring();
        startHttpServer();
    }

    private static void startHealthMonitoring() {
        scheduler.scheduleAtFixedRate(() -> {
            HealthMetrics metrics = collectMetrics();
            cache.put("data", metrics);
        }, 0, 1, TimeUnit.MINUTES);
    }

    private static HealthMetrics collectMetrics() {
        Runtime runtime = Runtime.getRuntime();
        OperatingSystemMXBean osBean = ManagementFactory.getPlatformMXBean(OperatingSystemMXBean.class);
        File rootDisk = new File("/");

        long memoryUsed = runtime.totalMemory() - runtime.freeMemory();
        long memoryMax = runtime.maxMemory();
        double cpuLoad = osBean.getSystemLoadAverage();
        long diskUsed = rootDisk.getTotalSpace() - rootDisk.getUsableSpace();
        long diskTotal = rootDisk.getTotalSpace();

        return new HealthMetrics(memoryUsed, memoryMax, cpuLoad, diskUsed, diskTotal, Instant.now().toEpochMilli());
    }

    private static void startHttpServer() throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/health", exchange -> {
            HealthMetrics metrics = cache.get("data");
            if (metrics == null || (Instant.now().toEpochMilli() - metrics.getTimestamp()) > 60000) {
                exchange.sendResponseHeaders(503, 0);
                exchange.close();
                return;
            }

            String response = String.format(
                    "{\"memory\":{\"used\":%d,\"max\":%d},\"cpuLoad\":%.2f,\"disk\":{\"used\":%d,\"total\":%d},\"timestamp\":%d}",
                    metrics.getMemoryUsed(), metrics.getMemoryMax(), metrics.getCpuLoad(),
                    metrics.getDiskUsed(), metrics.getDiskTotal(), metrics.getTimestamp()
            );

            exchange.getResponseHeaders().set("Content-Type", "application/json");
            exchange.sendResponseHeaders(200, response.getBytes().length);
            exchange.getResponseBody().write(response.getBytes());
            exchange.close();
        });
        server.start();
    }

    static class HealthMetrics {
        private final long memoryUsed;
        private final long memoryMax;
        private final double cpuLoad;
        private final long diskUsed;
        private final long diskTotal;
        private final long timestamp;

        public HealthMetrics(long memoryUsed, long memoryMax, double cpuLoad, long diskUsed, long diskTotal, long timestamp) {
            this.memoryUsed = memoryUsed;
            this.memoryMax = memoryMax;
            this.cpuLoad = cpuLoad;
            this.diskUsed = diskUsed;
            this.diskTotal = diskTotal;
            this.timestamp = timestamp;
        }

        public long getMemoryUsed() { return memoryUsed; }
        public long getMemoryMax() { return memoryMax; }
        public double getCpuLoad() { return cpuLoad; }
        public long getDiskUsed() { return diskUsed; }
        public long getDiskTotal() { return diskTotal; }
        public long getTimestamp() { return timestamp; }
    }
}
