use anyhow::{Context, Result};
use clap::Parser;
use serde_json::Value;
use std::path::PathBuf;

#[derive(Parser, Debug)]
#[command(version, about)]
struct Args {
    input_files: Vec<PathBuf>,
    #[arg(short, long)]
    output_file: PathBuf,
}

async fn run() -> Result<()> {
    let args = Args::parse();
    let mut values = Vec::new();

    for path in &args.input_files {
        let content = tokio::fs::read_to_string(path)
            .await
            .with_context(|| format!("Failed to read file: {:?}", path))?;
        let value: Value = serde_json::from_str(&content)
            .with_context(|| format!("Invalid JSON in file: {:?}", path))?;
        values.push(value);
    }

    if values.is_empty() {
        anyhow::bail!("No input files provided");
    }

    let first_value = &values[0];
    let is_object = first_value.is_object();
    let is_array = first_value.is_array();

    for (i, value) in values.iter().enumerate().skip(1) {
        if (is_object && !value.is_object()) || (is_array && !value.is_array()) {
            anyhow::bail!("Schema mismatch in file {}", i + 1);
        }
    }

    let merged_value = if is_object {
        let mut merged = serde_json::Map::new();
        for (idx, value) in values.into_iter().enumerate() {
            let obj = value.as_object().unwrap();
            for (k, v) in obj {
                if merged.contains_key(k) {
                    anyhow::bail!("Duplicate key '{}' in file {}", k, idx + 1);
                }
                merged.insert(k, v);
            }
        }
        Value::Object(merged)
    } else if is_array {
        let mut merged = Vec::new();
        for arr in values {
            merged.extend(arr.as_array().unwrap().clone());
        }
        Value::Array(merged)
    } else {
        Value::Array(values)
    };

    let output = serde_json::to_string_pretty(&merged_value)?;
    tokio::fs::write(&args.output_file, output)
        .await
        .with_context(|| format!("Failed to write to {:?}", args.output_file))?;

    Ok(())
}

#[tokio::main]
async fn main() -> Result<()> {
    run().await
}
