from datetime import datetime
from typing import Any, Dict, Optional, Tuple
import requests

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

CONFIG = {"api_url": "https://api.example.com/data", "db_name": "processed_data.db"}

def setup_database() -> None:
    with sqlite3.connect(CONFIG["db_name"]) as conn:
        conn.execute(
            """CREATE TABLE IF NOT EXISTS main_data (
                id INTEGER PRIMARY KEY,
                api_id INTEGER,
                title TEXT,
                processed_date TEXT
            )"""
        )
        conn.execute(
            """CREATE TABLE IF NOT EXISTS related_data (
                main_id INTEGER,
                attribute TEXT,
                value TEXT,
                FOREIGN KEY(main_id) REFERENCES main_data(id)
            )"""
        )

def process_record(record: Dict[str, Any]) -> Optional[Tuple[Any, ...]]:
    try:
        if (date_str := record.get("date")) is not None:
            processed_date = datetime.strptime(date_str, "%Y-%m-%dT%H:%M:%S").isoformat()
        else:
            processed_date = None

        return (
            record["id"],
            record.get("title"),
            processed_date,
            record.get("attributes"),
        )
    except (KeyError, ValueError) as e:
        logger.warning(f"Data inconsistency: {e} in record {record.get('id')}")
        return None

def fetch_api_data() -> Optional[Dict[str, Any]]:
    try:
        if (response := requests.get(CONFIG["api_url"])) and response.status_code == 200:
            return response.json()
        logger.error(f"API request failed: {response.status_code}")
    except requests.exceptions.RequestException as e:
        logger.error(f"Network error: {e}")
    return None

def main() -> None:
    setup_database()
    api_data = fetch_api_data()
    if not api_data:
        return

    processed, inconsistencies = 0, 0
    records_to_insert = []
    related_to_insert = []

    for record in api_data.get("results", []):
        if (processed_data := process_record(record)) is not None:
            main_id, title, date, attributes = processed_data
            records_to_insert.append((main_id, title, date))
            for attr, val in (attributes or {}).items():
                related_to_insert.append((main_id, attr, str(val)))
            processed += 1
        else:
            inconsistencies += 1

    try:
        with sqlite3.connect(CONFIG["db_name"]) as conn:
            conn.executemany(
                "INSERT INTO main_data (api_id, title, processed_date) VALUES (?, ?, ?)",
                records_to_insert,
            )
            conn.executemany(
                "INSERT INTO related_data (main_id, attribute, value) VALUES (?, ?, ?)",
                related_to_insert,
            )
    except sqlite3.Error as e:
        logger.error(f"Database error: {e}")
        return

    logger.info(f"Processed {processed} records with {inconsistencies} inconsistencies")

if __name__ == "__main__":
    main()
