import com.sun.net.httpserver.*;
import java.io.*;
import java.net.*;
import java.nio.charset.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.*;

public class UrlShortener {
    private static final String API_KEY = "SECURE_KEY";
    private static final UrlStore store = new UrlStore();

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/shorten", new ShortenHandler());
        server.createContext("/", new RedirectHandler());
        server.setExecutor(Executors.newCachedThreadPool());
        server.start();
    }

    static class ShortenHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!exchange.getRequestMethod().equalsIgnoreCase("POST")) {
                sendResponse(exchange, 405, "");
                return;
            }
            if (!API_KEY.equals(exchange.getRequestHeaders().getFirst("Authorization"))) {
                sendResponse(exchange, 401, "");
                return;
            }
            String longUrl = new String(exchange.getRequestBody().readAllBytes(), StandardCharsets.UTF_8);
            String alias = generateAlias();
            HttpClient.newHttpClient().sendAsync(
                HttpRequest.newBuilder().uri(URI.create(longUrl)).HEAD().build(),
                HttpResponse.BodyHandlers.discarding()
            ).thenAccept(res -> {
                if (res.statusCode() >= 200 && res.statusCode() < 300) {
                    store.add(alias, longUrl);
                    sendResponse(exchange, 200, alias);
                } else {
                    sendResponse(exchange, 400, "Invalid URL");
                }
            }).exceptionally(e -> {
                sendResponse(exchange, 400, "Invalid URL");
                return null;
            });
        }

        private String generateAlias() {
            return UUID.randomUUID().toString().replace("-", "").substring(0, 8);
        }
    }

    static class RedirectHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            String alias = exchange.getRequestURI().getPath().substring(1);
            String url = store.getUrl(alias);
            if (url == null) {
                sendResponse(exchange, 404, "");
                return;
            }
            store.incrementCount(alias);
            exchange.getResponseHeaders().add("Location", url);
            exchange.sendResponseHeaders(302, -1);
            exchange.close();
        }
    }

    static void sendResponse(HttpExchange ex, int code, String body) {
        try {
            ex.sendResponseHeaders(code, body.length());
            try (OutputStream os = ex.getResponseBody()) {
                os.write(body.getBytes());
            }
        } catch (IOException e) { e.printStackTrace(); }
    }
}

class UrlStore {
    private final ConcurrentHashMap<String, UrlEntry> map = new ConcurrentHashMap<>();

    void add(String alias, String url) {
        map.put(alias, new UrlEntry(url));
    }

    String getUrl(String alias) {
        UrlEntry entry = map.get(alias);
        return entry == null ? null : entry.url;
    }

    void incrementCount(String alias) {
        UrlEntry entry = map.get(alias);
        if (entry != null) entry.count.incrementAndGet();
    }

    private static class UrlEntry {
        final String url;
        final AtomicInteger count = new AtomicInteger();

        UrlEntry(String url) { this.url = url; }
    }
}
