import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Pattern;
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;

public class AnalyticsDaemon {

    private static final Pattern IP_PATTERN = Pattern.compile("\\b(?:\\d{1,3}\\.){3}\\d{1,3}\\b");
    private static final ConcurrentHashMap<String, Integer> threatScores = new ConcurrentHashMap<>();

    public static void main(String[] args) throws InterruptedException {
        if (args.length < 2) {
            System.err.println("Usage: java AnalyticsDaemon <logFilePath> <blacklistUrl>");
            System.exit(1);
        }

        String logPath = args[0];
        String blacklistUrl = args[1];
        HttpClient httpClient = HttpClient.newHttpClient();

        Thread monitorThread = new Thread(() -> monitorLog(logPath, blacklistUrl, httpClient));
        monitorThread.setDaemon(true);
        monitorThread.start();
        monitorThread.join();
    }

    private static void monitorLog(String logPath, String blacklistUrl, HttpClient httpClient) {
        try (BufferedReader reader = new BufferedReader(new FileReader(logPath))) {
            String line;
            while (true) {
                line = reader.readLine();
                if (line != null) processLine(line, blacklistUrl, httpClient);
                else Thread.sleep(1000);
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    private static void processLine(String line, String blacklistUrl, HttpClient httpClient) {
        var matcher = IP_PATTERN.matcher(line);
        while (matcher.find()) {
            String ip = matcher.group();
            checkBlacklist(ip, blacklistUrl, httpClient);
        }
    }

    private static void checkBlacklist(String ip, String blacklistUrl, HttpClient httpClient) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(blacklistUrl + "?ip=" + ip))
                .GET()
                .build();

        httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApply(HttpResponse::body)
                .thenAccept(response -> {
                    if ("true".equalsIgnoreCase(response)) {
                        threatScores.merge(ip, 1, Integer::sum);
                    }
                })
                .exceptionally(e -> {
                    System.err.println("Error checking IP " + ip + ": " + e.getMessage());
                    return null;
                });
    }
}
