import java.sql.*;
import java.util.concurrent.CompletableFuture;
import javax.sql.DataSource;

public class MediaRepository {
    private final DataSource dataSource;

    public MediaRepository(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    public CompletableFuture<Void> save(Media media) {
        return CompletableFuture.runAsync(() -> {
            try (Connection conn = dataSource.getConnection()) {
                conn.setAutoCommit(false);
                PreparedStatement stmt = conn.prepareStatement(
                    "INSERT INTO media (id, type, title, detail) VALUES (?, ?, ?, ?)");
                if (media instanceof Book book) {
                    stmt.setString(1, book.id());
                    stmt.setString(2, "BOOK");
                    stmt.setString(3, book.title());
                    stmt.setString(4, book.author() + ";" + book.isbn());
                } else if (media instanceof Journal journal) {
                    stmt.setString(1, journal.id());
                    stmt.setString(2, "JOURNAL");
                    stmt.setString(3, journal.title());
                    stmt.setString(4, journal.editor() + ";" + journal.issue());
                } else if (media instanceof Magazine magazine) {
                    stmt.setString(1, magazine.id());
                    stmt.setString(2, "MAGAZINE");
                    stmt.setString(3, magazine.title());
                    stmt.setString(4, magazine.publisher() + ";" + magazine.date());
                }
                stmt.executeUpdate();
                conn.commit();
            } catch (SQLException e) {
                throw new RuntimeException(e);
            }
        });
    }
}

