use chrono::{DateTime, Local};
use notify::{Config, Event, EventKind, RecommendedWatcher, Watcher};
use serde::Serialize;
use sha2::{Digest, Sha256};
use std::path::Path;
use std::sync::Arc;
use tokio::io::AsyncWriteExt;
use tokio::sync::Mutex;

#[derive(Serialize)]
struct LogEntry {
    event_timestamp: DateTime<Local>,
    file_name: String,
    modification_time: DateTime<Local>,
    hash: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <directory>", args[0]);
        std::process::exit(1);
    }
    let dir = &args[1];

    let log_file = tokio::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open("file_monitor.log")
        .await?;
    let log_file = Arc::new(Mutex::new(log_file));

    let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel();

    let mut watcher = RecommendedWatcher::new(
        move |res| {
            tx.send(res).unwrap();
        },
        Config::default(),
    )?;

    watcher.watch(Path::new(dir), notify::RecursiveMode::NonRecursive)?;

    while let Some(res) = rx.recv().await {
        match res {
            Ok(event) => {
                let log_file = Arc::clone(&log_file);
                tokio::spawn(async move {
                    handle_event(event, log_file).await;
                });
            }
            Err(e) => eprintln!("Watch error: {:?}", e),
        }
    }

    Ok(())
}

async fn handle_event(event: Event, log_file: Arc<Mutex<tokio::fs::File>>) {
    if !matches!(
        event.kind,
        EventKind::Create(_) | EventKind::Modify(_)
    ) {
        return;
    }

    for path in event.paths {
        let metadata = match tokio::fs::metadata(&path).await {
            Ok(m) => m,
            Err(_) => continue,
        };
        if metadata.is_dir() {
            continue;
        }

        let modification_time = match metadata.modified() {
            Ok(t) => DateTime::<Local>::from(t),
            Err(_) => continue,
        };

        let contents = match tokio::fs::read(&path).await {
            Ok(c) => c,
            Err(_) => continue,
        };

        let mut hasher = Sha256::new();
        hasher.update(&contents);
        let hash = format!("{:x}", hasher.finalize());

        let log_entry = LogEntry {
            event_timestamp: Local::now(),
            file_name: path.to_string_lossy().to_string(),
            modification_time,
            hash,
        };

        let log_line = match serde_json::to_string(&log_entry) {
            Ok(line) => line,
            Err(_) => continue,
        };

        let mut file = log_file.lock().await;
        if let Err(e) = file.write_all(log_line.as_bytes()).await {
            eprintln!("Write error: {:?}", e);
        }
        if let Err(e) = file.write_all(b"\n").await {
            eprintln!("Write error: {:?}", e);
        }
    }
}
