import logging
import json
import os
import time
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler
from pymongo import MongoClient
from pymongo.errors import PyMongoError

logging.basicConfig(
    filename='directory_monitor.log',
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)

class MongoHandler:
    def __init__(self):
        self.client = MongoClient(
            "mongodb://username:password@localhost:27017/",
            tls=True,
            tlsAllowInvalidCertificates=True
        )
        self.db = self.client['mydatabase']['mycollection']

    def update_data(self, document):
        try:
            match document:
                case {"_id": str(id), **rest}:
                    self.db.update_one(
                        {"_id": id},
                        {"$set": rest},
                        upsert=True
                    )
                    logging.info(f"Updated document with _id: {id}")
                case _:
                    logging.error("Document structure validation failed")
        except PyMongoError as e:
            logging.error(f"MongoDB error: {str(e)}")

class JSONHandler(FileSystemEventHandler):
    def __init__(self, mongo_handler):
        self.mongo = mongo_handler

    def on_modified(self, event):
        if event.is_directory:
            return
        self.process_file(event.src_path)

    def on_created(self, event):
        if event.is_directory:
            return
        self.process_file(event.src_path)

    def process_file(self, file_path):
        if not file_path.endswith('.json'):
            return
        try:
            with open(file_path, 'r') as f:
                data = json.load(f)
                self.mongo.update_data(data)
            logging.info(f"Processed file: {os.path.basename(file_path)}")
        except (json.JSONDecodeError, IOError) as e:
            logging.error(f"File error: {str(e)}")
        except Exception as e:
            logging.error(f"Unexpected error: {str(e)}")

if __name__ == "__main__":
    mongo_handler = MongoHandler()
    event_handler = JSONHandler(mongo_handler)
    observer = Observer()
    observer.schedule(event_handler, '/path/to/monitor', recursive=False)
    observer.start()
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        observer.stop()
    observer.join()
