import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.List;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

public class WeatherApp {

    record City(String name, double latitude, double longitude) {}

    private static final List<City> CITIES = List.of(
        new City("London", 51.5085, -0.1257),
        new City("New York", 40.7143, -74.006),
        new City("Tokyo", 35.6895, 139.6917)
    );

    private static final HttpClient HTTP_CLIENT = HttpClient.newBuilder()
        .version(HttpClient.Version.HTTP_3)
        .connectTimeout(Duration.ofSeconds(10))
        .build();

    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    private static final ScheduledExecutorService SCHEDULER = Executors.newScheduledThreadPool(1);

    public static void main(String[] args) {
        SCHEDULER.scheduleAtFixedRate(() -> {
            for (City city : CITIES) {
                try {
                    String url = String.format(
                        "https://api.open-meteo.com/v1/forecast?latitude=%.4f&longitude=%.4f&current_weather=true&hourly=precipitation",
                        city.latitude(), city.longitude()
                    );
                    HttpRequest request = HttpRequest.newBuilder()
                        .uri(URI.create(url))
                        .timeout(Duration.ofSeconds(10))
                        .GET()
                        .build();

                    HttpResponse<String> response = HTTP_CLIENT.send(request, HttpResponse.BodyHandlers.ofString());

                    if (response.statusCode() != 200) {
                        System.err.printf("Error fetching data for %s: HTTP %d%n", city.name(), response.statusCode());
                        continue;
                    }

                    JsonNode root = OBJECT_MAPPER.readTree(response.body());
                    JsonNode currentWeather = root.path("current_weather");
                    JsonNode hourlyPrecip = root.path("hourly").path("precipitation");

                    double temp = currentWeather.path("temperature").asDouble();
                    double wind = currentWeather.path("windspeed").asDouble();
                    double precip = hourlyPrecip.isArray() && hourlyPrecip.size() > 0 ? hourlyPrecip.get(0).asDouble() : 0.0;

                    System.out.printf("%s - Temperature: %.1f°C, Wind Speed: %.1f km/h, Precipitation: %.1f mm%n",
                        city.name(), temp, wind, precip);

                } catch (Exception e) {
                    System.err.printf("Error processing %s: %s%n", city.name(), e.getMessage());
                }
            }
            System.out.println("-------------------");
        }, 0, 5, TimeUnit.MINUTES);
    }
}
