import java.sql.*;
import java.util.List;
import java.util.concurrent.*;
import java.util.stream.Collectors;

sealed interface RssEntry permits NewsItem, InvalidEntry {}
record NewsItem(String title, String pubDate, String feedUrl) implements RssEntry {}
record InvalidEntry(String feedUrl) implements RssEntry {}

public class RssFeedProcessor {
    private final ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();
    private final List<String> feedUrls;

    public RssFeedProcessor(List<String> feedUrls) {
        this.feedUrls = feedUrls;
    }

    public void processAllFeeds() {
        List<Future<?>> futures = feedUrls.stream()
                .map(url -> executor.submit(() -> processFeed(url)))
                .collect(Collectors.toList());

        futures.forEach(future -> {
            try {
                future.get();
            } catch (InterruptedException | ExecutionException e) {
                Thread.currentThread().interrupt();
            }
        });
        executor.shutdown();
    }

    private void processFeed(String url) {
        try {
            Document doc = Jsoup.connect(url).get();
            List<RssEntry> entries = new RssParser().parse(doc, url);
            entries.stream()
                   .filter(NewsItem.class::isInstance)
                   .forEach(entry -> new DatabaseManager().saveNewsItem((NewsItem) entry));
        } catch (Exception e) {
            System.err.println("Error processing feed: " + url);
        }
    }

    public static void main(String[] args) {
        new RssFeedProcessor(List.of(
                "https://example.com/feed1.rss",
                "https://example.com/feed2.rss"
        )).processAllFeeds();
    }
}

class RssParser {
    List<RssEntry> parse(Document doc, String feedUrl) {
        return doc.select("item").stream()
                .map(item -> {
                    String title = "";
                    String pubDate = "";
                    for (Element element : item.children()) {
                        switch (element.tagName()) {
                            case "title" -> title = element.text();
                            case "pubDate" -> pubDate = element.text();
                        }
                    }
                    return (!title.isEmpty() && !pubDate.isEmpty())
                            ? new NewsItem(title, pubDate, feedUrl)
                            : new InvalidEntry(feedUrl);
                })
                .collect(Collectors.toList());
    }
}

class DatabaseManager {
    private Connection connect() throws SQLException {
        return DriverManager.getConnection("jdbc:sqlite:news.db");
    }

    void saveNewsItem(NewsItem item) {
        try (Connection conn = connect();
             PreparedStatement ps = conn.prepareStatement(
                     "CREATE TABLE IF NOT EXISTS news (title TEXT, pubDate TEXT, feedUrl TEXT)")) {
            ps.execute();
        } catch (SQLException e) {
            throw new RuntimeException(e);
        }

        try (Connection conn = connect();
             PreparedStatement ps = conn.prepareStatement(
                     "INSERT INTO news (title, pubDate, feedUrl) VALUES (?, ?, ?)")) {
            ps.setString(1, item.title());
            ps.setString(2, item.pubDate());
            ps.setString(3, item.feedUrl());
            ps.executeUpdate();
        } catch (SQLException e) {
            throw new RuntimeException(e);
        }
    }
}
