use anyhow::{Context, Result};
use async_std::fs;
use clap::Parser;
use diesel::dsl::sql;
use diesel::prelude::*;
use diesel_async::{AsyncConnection, AsyncPgConnection, RunQueryDsl};
use std::collections::BTreeSet;
use std::path::Path;

#[derive(Parser)]
#[clap(version)]
struct Args {
    #[clap(long, default_value = "postgres://localhost/mydb")]
    database_url: String,
    #[clap(long, default_value = "migrations")]
    migrations_dir: String,
}

#[async_std::main]
async fn main() -> Result<()> {
    let args = Args::parse();
    let mut conn = AsyncPgConnection::establish(&args.database_url)
        .await
        .context("Failed to connect to database")?;

    sql_query(
        r#"
        CREATE TABLE IF NOT EXISTS __diesel_schema_migrations (
            version VARCHAR(50) PRIMARY KEY,
            applied_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
        )
        "#,
    )
    .execute(&mut conn)
    .await
    .context("Failed to create migrations table")?;

    let applied: BTreeSet<String> = diesel::sql_query("SELECT version FROM __diesel_schema_migrations")
        .load::<(String,)>(&mut conn)
        .await
        .context("Failed to load applied migrations")?
        .into_iter()
        .map(|(v,)| v)
        .collect();

    let migrations_dir = Path::new(&args.migrations_dir);
    let mut entries = fs::read_dir(migrations_dir)
        .await
        .context("Failed to read migrations directory")?;

    let mut migrations = Vec::new();
    while let Some(entry) = entries.next().await {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
                if let Some((ver, _)) = name.split_once('_') {
                    migrations.push((ver.to_string(), path.join("up.sql")));
                }
            }
        }
    }
    migrations.sort_by(|a, b| a.0.cmp(&b.0));

    for (version, path) in migrations {
        if applied.contains(&version) {
            continue;
        }

        let sql = fs::read_to_string(&path)
            .await
            .with_context(|| format!("Failed to read migration file: {:?}", path))?;

        let mut transaction = conn
            .transaction()
            .await
            .context("Failed to start transaction")?;

        match sql_query(&sql).execute(&mut transaction).await {
            Ok(_) => {
                diesel::insert_into(sql::<diesel::sql_types::Void>("__diesel_schema_migrations"))
                    .values(("version", &version))
                    .execute(&mut transaction)
                    .await
                    .context("Failed to record migration")?;

                transaction.commit().await.context("Failed to commit transaction")?;
                println!("Applied migration {}", version);
            }
            Err(e) => {
                transaction.rollback().await.context("Failed to rollback transaction")?;
                return Err(e).with_context(|| format!("Migration {} failed", version));
            }
        }
    }

    Ok(())
}
