import java.nio.file.*;
import java.io.IOException;
import java.time.Instant;

public class ConfigFileWatcher {
    private static final Path LOG_PATH = Paths.get("changes.log");

    public static void main(String[] args) throws IOException {
        if (args.length == 0) {
            System.err.println("Provide directories to monitor");
            return;
        }

        WatchService watchService = FileSystems.getDefault().newWatchService();
        for (String dir : args) {
            Path path = Paths.get(dir);
            if (!Files.isDirectory(path)) {
                System.err.println("Invalid directory: " + dir);
                continue;
            }
            path.register(watchService, StandardWatchEventKinds.ENTRY_MODIFY, 
                          StandardWatchEventKinds.ENTRY_CREATE, 
                          StandardWatchEventKinds.ENTRY_DELETE);
        }

        while (true) {
            WatchKey key;
            try {
                key = watchService.take();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                return;
            }

            for (WatchEvent<?> event : key.pollEvents()) {
                Path dir = (Path) key.watchable();
                Path file = dir.resolve((Path) event.context());
                String logEntry = String.format(
                    "{\"event\": \"%s\", \"timestamp\": \"%s\", \"file\": \"%s\"}%n",
                    event.kind().name(), Instant.now(), file);
                try {
                    Files.write(LOG_PATH, logEntry.getBytes(), 
                               StandardOpenOption.CREATE, StandardOpenOption.APPEND);
                } catch (IOException ex) {
                    System.err.println("Logging failed: " + ex.getMessage());
                }
            }

            if (!key.reset()) {
                System.err.println("Watch key invalid");
                break;
            }
        }
    }
}
