import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.*;
import java.nio.file.*;

record Config(int intervalSeconds, List<String> urls) {}

class ConfigLoader {
    static Config load(String filename) throws Exception {
        Properties props = new Properties();
        props.load(Files.newInputStream(Paths.get(filename)));
        int interval = Integer.parseInt(props.getProperty("interval"));
        List<String> urls = new ArrayList<>();
        for (String key : props.stringPropertyNames()) {
            if (key.startsWith("url.")) urls.add(props.getProperty(key));
        }
        return new Config(interval, urls);
    }
}

class HealthMonitor {
    private static final HttpClient httpClient = HttpClient.newHttpClient();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
    private final Config config;

    HealthMonitor(Config config) {
        this.config = config;
    }

    void start() {
        scheduler.scheduleAtFixedRate(this::checkServers, 0, config.intervalSeconds(), TimeUnit.SECONDS);
    }

    private void checkServers() {
        config.urls().forEach(url -> {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(url))
                    .timeout(Duration.ofSeconds(10))
                    .build();

            httpClient.sendAsync(request, HttpResponse.BodyHandlers.discarding())
                    .thenApplyAsync(response -> {
                        log(url, response.statusCode(), null);
                        if (response.statusCode() >= 400) alert(url, "HTTP error: " + response.statusCode());
                        return response;
                    })
                    .exceptionally(e -> {
                        log(url, -1, e.getMessage());
                        alert(url, "Connection failed: " + e.getCause().getMessage());
                        return null;
                    });
        });
    }

    private void log(String url, int status, String error) {
        String logEntry = String.format("[%s] %s - Status: %d - Error: %s%n",
                new Date(), url, status, error != null ? error : "None");
        try {
            Files.write(Paths.get("health.log"), logEntry.getBytes(), StandardOpenOption.CREATE, StandardOpenOption.APPEND);
        } catch (Exception ignored) {}
    }

    private void alert(String url, String message) {
        System.err.printf("[ALERT] %s - %s%n", url, message);
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        HealthMonitor monitor = new HealthMonitor(ConfigLoader.load("config.properties"));
        monitor.start();
    }
}
