import argparse
import os
import tokenize
import json
import concurrent.futures

def extract_comments(filepath, /) -> list:
    comments = []
    try:
        with open(filepath, 'rb') as f:
            for tok in tokenize.tokenize(f.readline):
                if tok.type == tokenize.COMMENT:
                    comments.append({'line': tok.start[0], 'text': tok.string.strip()})
    except Exception as e:
        print(f"Error processing {filepath}: {e}")
    return comments

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('directory')
    parser.add_argument('output_json')
    args = parser.parse_args()

    filepaths = [
        os.path.join(root, file)
        for root, _, files in os.walk(args.directory)
        for file in files
        if (suffix := os.path.splitext(file)[1].lower()) == '.py'
    ]

    comments_dict = {}
    with concurrent.futures.ThreadPoolExecutor() as executor:
        future_to_file = {executor.submit(extract_comments, fp): fp for fp in filepaths}
        for future in concurrent.futures.as_completed(future_to_file):
            fp = future_to_file[future]
            comments_dict[fp] = future.result()

    with open(args.output_json, 'w') as f:
        json.dump(comments_dict, f, indent=2)

if __name__ == '__main__':
    main()
