use async_std::{
    net::{TcpListener, TcpStream},
    prelude::*,
    task,
};
use log::{error, info};
use serde::{Deserialize, Serialize};
use std::{env, time::Duration};

#[derive(Debug, Serialize, Deserialize)]
struct DataPayload {
    id: u32,
    value: f64,
}

async fn handle_client(mut stream: TcpStream) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let mut buf = Vec::new();
    stream.read_to_end(&mut buf).await?;

    let payload: DataPayload = serde_json::from_slice(&buf)?;
    info!("Received payload: {:?}", payload);

    let processed = business_logic(payload)?;
    let response = serde_json::to_vec(&processed)?;
    stream.write_all(&response).await?;
    stream.flush().await?;

    Ok(())
}

fn business_logic(payload: DataPayload) -> Result<DataPayload, Box<dyn std::error::Error + Send + Sync>> {
    // Custom transformation: Increment value by 10%
    Ok(DataPayload {
        id: payload.id,
        value: payload.value * 1.10,
    })
}

#[async_std::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    let args: Vec<String> = env::args().collect();
    let port = args.get(1).ok_or("Missing port argument")?;
    let listener = TcpListener::bind(format!("0.0.0.0:{}", port)).await?;
    info!("Listening on port {}", port);

    while let Ok((stream, _)) = listener.accept().await {
        task::spawn(async move {
            match handle_client(stream).await {
                Ok(_) => info!("Request processed successfully"),
                Err(e) => error!("Error processing request: {:?}", e),
            }
        });
    }

    Ok(())
}
