import argparse
import json
from pathlib import Path
from collections import defaultdict
import matplotlib.pyplot as plt
import logging

def parse_args():
    parser = argparse.ArgumentParser(description='Process JSON log files')
    parser.add_argument('--path', type=Path, required=True, help='Path to log file/directory')
    parser.add_argument('--verbose', action='store_true', help='Enable verbose logging')
    parser.add_argument('--output', type=str, default='log_analysis.png', help='Output filename for visualization')
    return parser.parse_args()

def configure_logging(verbose):
    logging.basicConfig(level=logging.DEBUG if verbose else logging.INFO)

def process_log_entry(entry, counters):
    try:
        counters['types'][entry['error_type']] += 1
        counters['severities'][entry['severity']] += 1
    except KeyError as e:
        logging.warning(f"Missing key in log entry: {e}")

def process_file(path, counters):
    try:
        with path.open('r') as f:
            for line in f:
                try:
                    process_log_entry(json.loads(line), counters)
                except json.JSONDecodeError as e:
                    logging.error(f"Invalid JSON in {path}: {e}")
    except OSError as e:
        logging.error(f"Error reading {path}: {e}")

def generate_visualization(counters, output_file):
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(12, 6))

    types, counts = zip(*counters['types'].items())
    ax1.bar(types, counts)
    ax1.set_title('Errors by Type')
    ax1.tick_params(axis='x', rotation=45)

    severities, values = zip(*counters['severities'].items())
    ax2.pie(values, labels=severities, autopct='%1.1f%%')
    ax2.set_title('Error Severity Distribution')

    plt.tight_layout()
    plt.savefig(output_file)
    plt.close()

def main():
    args = parse_args()
    configure_logging(args.verbose)

    if not args.path.exists():
        logging.error(f"Path {args.path} does not exist")
        return

    counters = {'types': defaultdict(int), 'severities': defaultdict(int)}

    try:
        if args.path.is_file():
            process_file(args.path, counters)
        elif args.path.is_dir():
            for log_file in args.path.glob('*.json'):
                process_file(log_file, counters)
    except Exception as e:
        logging.error(f"Critical processing error: {e}")
        if isinstance(e, ExceptionGroup):
            for sub_e in e.exceptions:
                logging.error(f"Sub-error: {sub_e}")

    generate_visualization(counters, args.output)

if __name__ == '__main__':
    main()
