import java.time.Instant;
import java.util.Properties;
import java.util.concurrent.ExecutionException;
import org.apache.kafka.clients.consumer.*;
import org.apache.kafka.common.serialization.StringDeserializer;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.zaxxer.hikari.HikariDataSource;
import javax.sql.DataSource;
import java.sql.*;

public class TransactionService {

    private static final String TOPIC = "transactions";
    private static final ObjectMapper mapper = new ObjectMapper();
    private static final DataSource dataSource = createDataSource();

    public static void main(String[] args) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "transaction-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());

        try (KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props)) {
            consumer.subscribe(java.util.Collections.singleton(TOPIC));
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(java.time.Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    processTransaction(record.value());
                }
                consumer.commitSync();
            }
        }
    }

    private static void processTransaction(String json) {
        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);
            TransactionData transaction = mapper.readValue(json, TransactionData.class);

            if (validateTransaction(transaction)) {
                if (transaction.type() instanceof Purchase) {
                    persistTransaction(conn, transaction);
                } else if (transaction.type() instanceof Refund) {
                    persistTransaction(conn, transaction);
                }
                conn.commit();
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static boolean validateTransaction(TransactionData t) {
        return t.amount() > 0 && t.customerId() != null && !t.customerId().isEmpty();
    }

    private static void persistTransaction(Connection conn, TransactionData t) throws SQLException {
        String sql = "INSERT INTO transactions (id, amount, customer_id, type, timestamp) VALUES (?, ?, ?, ?, ?)";
        try (PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, t.id());
            ps.setDouble(2, t.amount());
            ps.setString(3, t.customerId());
            ps.setString(4, t.type().getClass().getSimpleName());
            ps.setTimestamp(5, Timestamp.from(t.timestamp()));
            ps.executeUpdate();
        }
    }

    private static DataSource createDataSource() {
        HikariDataSource ds = new HikariDataSource();
        ds.setJdbcUrl("jdbc:postgresql://localhost:5432/ecommerce");
        ds.setUsername("postgres");
        ds.setPassword("postgres");
        return ds;
    }

    public sealed interface TransactionType permits Purchase, Refund {}
    public static final class Purchase implements TransactionType {}
    public static final class Refund implements TransactionType {}

    public record TransactionData(
        String id,
        double amount,
        String customerId,
        TransactionType type,
        Instant timestamp
    ) {}
}
