use std::path::{Path, PathBuf};
use aws_config::meta::region::RegionProviderChain;
use aws_sdk_s3::{Client as S3Client, Error as S3Error};
use aws_sdk_s3::primitives::ByteStream;
use notify::{Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use log::{error, info};
use tokio::sync::mpsc;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();
    let args: Vec<String> = std::env::args().collect();
    let (dir, bucket) = (&args[1], &args[2]);

    let region_provider = RegionProviderChain::default_provider();
    let config = aws_config::from_env().region(region_provider).load().await;
    let s3_client = S3Client::new(&config);

    let (tx, mut rx) = mpsc::unbounded_channel();
    let mut watcher: RecommendedWatcher = Watcher::new_immediate(move |res: Result<Event, _>| {
        if let Ok(event) = res {
            let _ = tx.send(event);
        }
    })?;

    watcher.watch(Path::new(dir), RecursiveMode::NonRecursive)?;

    while let Some(event) = rx.recv().await {
        if matches!(event.kind, EventKind::Create(_)) {
            for path in event.paths {
                if path.is_file() {
                    let client = s3_client.clone();
                    let bucket = bucket.clone();
                    let path = path.clone();

                    tokio::task::spawn_blocking(move || {
                        let runtime = tokio::runtime::Runtime::new().unwrap();
                        runtime.block_on(async {
                            match upload_file(&client, &bucket, &path).await {
                                Ok(_) => info!("Uploaded {:?}", path),
                                Err(e) => error!("Upload failed: {:?} - {}", path, e),
                            }
                        });
                    });
                }
            }
        }
    }
    Ok(())
}

async fn upload_file(client: &S3Client, bucket: &str, path: &PathBuf) -> Result<(), S3Error> {
    let body = ByteStream::from_path(path).await?;
    client.put_object()
        .bucket(bucket)
        .key(path.file_name().unwrap().to_str().unwrap())
        .body(body)
        .send()
        .await?;
    Ok(())
}
