import java.util.concurrent.*;
import java.util.*;
import java.time.Instant;
import com.google.gson.Gson;
import static spark.Spark.*;

record StockData(String symbol, double price, Instant timestamp) {}

record StockMetrics(double movingAverage, double fluctuation) {}

public class StockAnalysisApp {
    private static final int WINDOW_SIZE = 10;
    private static final ConcurrentHashMap<String, Deque<Double>> priceWindow = new ConcurrentHashMap<>();
    private static final ConcurrentHashMap<String, StockMetrics> latestMetrics = new ConcurrentHashMap<>();
    private static final BlockingQueue<StockData> dataQueue = new LinkedBlockingQueue<>();
    private static final ConcurrentLinkedQueue<String> alerts = new ConcurrentLinkedQueue<>();

    public static void main(String[] args) {
        ExecutorService processor = Executors.newVirtualThreadPerTaskExecutor();

        // Simulated streaming API
        Executors.newSingleThreadScheduledExecutor().scheduleAtFixedRate(() -> {
            StockData data = new StockData("AAPL", 150 + ThreadLocalRandom.current().nextDouble(-5, 5), Instant.now());
            dataQueue.add(data);
        }, 0, 100, TimeUnit.MILLISECONDS);

        // Parallel processing
        processor.submit(() -> {
            while (true) {
                StockData data = dataQueue.take();
                priceWindow.compute(data.symbol(), (k, v) -> {
                    Deque<Double> deque = v == null ? new ConcurrentLinkedDeque<>() : v;
                    deque.addLast(data.price());
                    if (deque.size() > WINDOW_SIZE) deque.removeFirst();
                    return deque;
                });

                Deque<Double> prices = priceWindow.get(data.symbol());
                double avg = prices.stream().mapToDouble(Double::doubleValue).average().orElse(0);
                double fluctuation = (data.price() - avg) / avg * 100;

                latestMetrics.put(data.symbol(), new StockMetrics(avg, fluctuation));

                if (Math.abs(fluctuation) > 2.0) {
                    alerts.offer("Significant fluctuation in " + data.symbol() + ": " + String.format("%.2f%%", fluctuation));
                }
            }
        });

        // REST API
        port(8080);
        Gson gson = new Gson();

