use clap::Parser;
use image::imageops::FilterType;
use std::path::{PathBuf, Path};
use std::sync::Arc;
use tokio::sync::Semaphore;
use walkdir::WalkDir;

#[derive(Parser, Clone)]
#[command(version, about)]
struct Args {
    source: PathBuf,
    dest: PathBuf,
    width: u32,
    height: u32,
}

#[tokio::main]
async fn main() {
    let args = Args::parse();
    let semaphore = Arc::new(Semaphore::new(10));
    let mut handles = vec![];

    for entry in WalkDir::new(&args.source)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.file_type().is_file())
        .filter(|e| is_image_file(e.path()))
    {
        let args = args.clone();
        let semaphore = Arc::clone(&semaphore);
        let entry_path = entry.into_path();

        handles.push(tokio::spawn(async move {
            let _permit = semaphore.acquire().await.unwrap();
            let dest_path = build_dest_path(&args.source, &args.dest, &entry_path);

            tokio::fs::create_dir_all(dest_path.parent().unwrap()).await.unwrap();
            tokio::fs::rename(&entry_path, &dest_path).await.unwrap();

            tokio::task::spawn_blocking(move || {
                let img = image::open(&dest_path).unwrap();
                img.resize_to_fit(args.width, args.height, FilterType::Lanczos3)
                    .save(&dest_path)
                    .unwrap();
            }).await.unwrap();
        }));
    }

    for handle in handles {
        handle.await.unwrap();
    }
}

fn is_image_file(path: &Path) -> bool {
    path.extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| matches!(ext.to_lowercase().as_str(), "jpg" | "jpeg" | "png"))
        .unwrap_or(false)
}

fn build_dest_path(source: &Path, dest: &Path, entry: &Path) -> PathBuf {
    let relative = entry.strip_prefix(source).unwrap();
    dest.join(relative)
}
