use flate2::Compression;
use flate2::write::GzEncoder;
use std::io::{self, BufRead};
use std::sync::{Arc, Condvar, Mutex};
use std::thread;
use std::collections::VecDeque;

struct SharedState {
    queue: VecDeque<String>,
    done: bool,
}

fn main() {
    let shared = Arc::new((Mutex::new(SharedState { queue: VecDeque::new(), done: false }), Condvar::new()));
    let num_threads = thread::available_parallelism().unwrap().get();
    let mut handles = Vec::new();

    for _ in 0..num_threads {
        let shared_clone = shared.clone();
        let handle = thread::spawn(move || worker(shared_clone));
        handles.push(handle);
    }

    let stdin = io::stdin();
    let (lock, cvar) = &*shared;
    for line in stdin.lock().lines() {
        let mut state = lock.lock().unwrap();
        state.queue.push_back(line.unwrap().trim().to_string());
        cvar.notify_one();
    }

    let mut state = lock.lock().unwrap();
    state.done = true;
    cvar.notify_all();
    drop(state);

    for handle in handles {
        handle.join().unwrap();
    }
}

fn worker(shared: Arc<(Mutex<SharedState>, Condvar)>) {
    let (lock, cvar) = &*shared;
    loop {
        let mut state = lock.lock().unwrap();
        while state.queue.is_empty() && !state.done {
            state = cvar.wait(state).unwrap();
        }
        if state.queue.is_empty() && state.done {
            break;
        }
        let filename = state.queue.pop_front().unwrap();
        drop(state);
        if let Err(e) = compress_file(&filename) {
            eprintln!("Error compressing {}: {}", filename, e);
        }
    }
}

fn compress_file(filename: &str) -> io::Result<()> {
    let input = std::fs::File::open(filename)?;
    let reader = io::BufReader::new(input);

    let output_path = format!("{}.gz", filename);
    let output = std::fs::File::create(&output_path)?;
    let mut encoder = GzEncoder::new(output, Compression::default());

    io::copy(&mut reader.into_inner(), &mut encoder)?;
    encoder.finish()?;
    Ok(())
}
