import com.google.gson.JsonObject;
import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;
import org.apache.tika.detect.DefaultDetector;
import org.apache.tika.language.detect.LanguageDetector;
import org.apache.tika.language.detect.LanguageResult;
import org.apache.tika.metadata.Metadata;
import org.apache.tika.parser.AutoDetectParser;
import org.apache.tika.parser.ParseContext;
import org.apache.tika.sax.BodyContentHandler;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import org.apache.tika.mime.MediaType;
import org.apache.tika.detect.Detector;

public class DocumentPreviewService {
    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/upload", new UploadHandler());
        server.setExecutor(null);
        server.start();
    }

    static class UploadHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equals(exchange.getRequestMethod())) {
                exchange.sendResponseHeaders(405, -1);
                return;
            }

            try (InputStream is = exchange.getRequestBody();
                 ByteArrayOutputStream bos = new ByteArrayOutputStream()) {
                byte[] buffer = new byte[1024];
                int bytesRead;
                while ((bytesRead = is.read(buffer)) != -1) {
                    bos.write(buffer, 0, bytesRead);
                }
                byte[] data = bos.toByteArray();

                Detector detector = new DefaultDetector();
                Metadata metadata = new Metadata();
                MediaType mediaType = detector.detect(new ByteArrayInputStream(data), metadata);
                String mimeType = mediaType.toString();

                if (!mimeType.matches("application/pdf|application/vnd.openxmlformats-officedocument.wordprocessingml.document|text/plain")) {
                    exchange.sendResponseHeaders(400, 0);
                    return;
                }

                BodyContentHandler handler = new BodyContentHandler();
                new AutoDetectParser().parse(new ByteArrayInputStream(data), handler, metadata, new ParseContext());
                String content = handler.toString();

                int wordCount = content.trim().isEmpty() ? 0 : content.split("\\s+").length;
                LanguageResult langResult = LanguageDetector.getDefault().detect(content, metadata);

                JsonObject response = new JsonObject();
                response.addProperty("fileType", mimeType);
                response.addProperty("wordCount", wordCount);
                response.addProperty("detectedLanguage", langResult.getLanguage());

                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.toString().getBytes().length);
                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(response.toString().getBytes());
                }
            } catch (Exception e) {
                exchange.sendResponseHeaders(500, -1);
            }
        }
    }
}
